mapper.select:
SELECT popup_zone_oid AS popupZoneOid, popup_zone_nm AS popupZoneNm, inq_cnt AS inqCnt, CASE WHEN open_yn = 'Y' THEN '공개' WHEN open_yn = 'N' THEN '미공개' ELSE '' END AS openState, DATE_FORMAT(reg_dt, '%Y-%m-%d') AS regDt FROM ${schema}.popup_zone
use_yn = 'Y'
AND ( popup_zone_oid LIKE CONCAT('%', #{keyword}, '%') OR popup_zone_nm LIKE CONCAT('%', #{keyword}, '%') )
AND open_yn = #{openYn}
AND DATE_FORMAT(reg_dt, '%Y-%m-%d') >= #{startDt} AND DATE_FORMAT(reg_dt, '%Y-%m-%d') <= #{endDt}
ORDER BY popup_zone_oid DESC

mapper.update:
